def expected(fname, mode):
    m = re.search(r'dmg08(?:_cgb04c)?_out([0-9A-Fa-f]+)', fname) if mode=='dmg' \
        else re.search(r'cgb04c_out([0-9A-Fa-f]+)', fname)
    return m.group(1).upper() if m else None

def check(fname, dump, mode):
    out = expected(fname, mode)
    if out is None: return None
    d = open(dump,'rb').read(); fb = struct.unpack('<%dI'%(len(d)//4), d)
    for i, ch in enumerate(out):
        g = FONT[int(ch,16)]
        for y in range(8):
            for x in range(8):
                if (fb[y*160 + i*8 + x] & 0xF8F8F8) != g[y*8+x]: return False
    return True

